INSERT INTO `helpwise_reply_examples` (`id`, `external_message_id`, `conversation_id`, `subject`, `sender_email`, `reply_body`, `sent_at`, `category`, `body_hash`, `created_at`, `updated_at`) VALUES (1,'','1','Re: Et lite spørsmål fra oss (etter vurderingen av din tekst)','wenche.braseth@gmail.com','Hei Wenche,\n\n\nIkke noe problem med turnusjobbing. Du får opptak av absolutt alt som skjer, og kan se det når det passer deg. Du kan også sende inn spørsmål på forhånd, hvis du ønsker det :-)\n\n\nHåper d','2026-03-25 13:20:48','general','794047e0dbfd92619c494f435046ace2','2026-03-27 18:21:11','2026-03-27 18:21:11'),(3,'inbox-4','1','Re: Et lite spørsmål fra oss (etter vurderingen av din tekst)','wenche.braseth@gmail.com','Hei igjen, Wenche,\n\n\nSelv takk for hyggelig samtale :-)\n\n\nJeg tror romankurset kan være noe for deg:\n\n\n https://www.forfatterskolen.no/course/121 \n\n\nSe info via lenken over – og se om det kan være noe','2026-03-25 10:07:47','general','a47ccf549a2a305d9b7d66c05812f95a','2026-03-27 18:22:55','2026-03-27 18:22:55'),(4,'inbox-6','1','Re: Et lite spørsmål fra oss (etter vurderingen av din tekst)','wenche.braseth@gmail.com','Hei Wenche,\n\n\nJa, ring gjerne meg: 411 23 555\n\n\nDato og klokkeslett passer fint :-)\n\n\nGleder meg til å snakkes!\n\n\nBeste hilsen,\n\nKristine S. Henningsen\nRektor, Forfatterskolen\n+47 411 23 555\n\nOn Thu, ','2026-03-12 23:11:32','general','b8af6b775d46d7292e41ea3b50eb5e4e','2026-03-27 18:22:55','2026-03-27 18:22:55'),(5,'inbox-9','2','Re: Innlogging fra pc`n går ikke','lksperre@gmail.com','Hei, tar kontakt litt senere i kveld.\n\n\n\n\n\n\n\n\n\n\nMvh\n\nSven Inge Henningsen - Easywrite/Forfatterskolen\nUtvikler\n\n https://cdn.helpwise.io/userSignatures/07ee10796cb17f5e70b7.1622489977.a84ba469b71c48ae','2026-03-25 14:59:18','general','48ae3fddb058e19963423cb45e66b263','2026-03-27 18:22:55','2026-03-27 18:22:55'),(6,'inbox-24','8','Re: Elev 1839 – første innlevering','siljewn@gmail.com','Tusen takk, Silje! Setter stor pris på hvor fleksibel du er :-) Eleven ble også veldig glad bå!\n\n\nBeste hilsen,\n\nKristine S. Henningsen\nRektor, Forfatterskolen\n+47 411 23 555\n\nOn Fri, Mar 20, 2026 at ','2026-03-21 18:42:33','general','5e7f764e2531f3bb9d1a758bfbb2c3ba','2026-03-27 18:22:55','2026-03-27 18:22:55'),(7,'inbox-26','8','Elev 1839 – første innlevering','siljewn@gmail.com','Hei Silje,\n\n\nHåper alt er så bra det kan være :-)\n\n\nElev Evy Krog - 1839 - har fått utsettelse på første innlevering til 7 april, altså over påske. Håper dette går greit. Hun klarte å miste alt hun ha','2026-03-20 20:39:18','general','eab704d29bd7eaeb81e5bd8d3a9b2634','2026-03-27 18:22:55','2026-03-27 18:22:55'),(8,'inbox-27','8','Re: Elev 20357 förste innlevering','siljewn@gmail.com','Supert, takk :)\n\n\nAlt godt,\nAnnina\n\n\nOn Fri, Mar 20, 2026 at 2:21 PM Silje Wiik Røssaak Nielsen <siljewn@gmail.com> wrote:\n> Takk! Jeg har ikke begynt å lese ennå, så det går fint.\n> \n> fre. 20. mars ','2026-03-20 12:27:17','general','66bbf366eb0add88163bf8fc9bb797af','2026-03-27 18:22:55','2026-03-27 18:22:55'),(9,'inbox-29','8','Elev 20357 förste innlevering','siljewn@gmail.com','Hei Silje!\n\n\nDin elevs 20357 brev för förste innlevering fattades från dokumentet. Jag har nu fått den av henne via mail och uppdaterat dokumentet i din editor. Jag ville informera dig om det ifall du','2026-03-20 12:01:18','general','dab41c1d993486b66b8e02c352f2d99f','2026-03-27 18:22:55','2026-03-27 18:22:55'),(10,'inbox-31','9','Re: Feil ved bestilling','kristola85@gmail.com','Hei Kristoffer,\n\nTakk for beskjed.\n\nBestillingssiden skal nå være oppe og gå igjen, hvis du har mulighet til å prøve på nytt. Vi ønsker helst at bestillingen går gjennom systemet, slik at vi får teste','2026-03-24 22:11:04','general','460810546e4b7ea98c1fa58c0309d7de','2026-03-27 18:22:55','2026-03-27 18:22:55'),(11,'inbox-37','12','Re: site.inquiry-message','gunn.helene.arsky@gmail.com','Klart det! Så moro – gratulerer .-)\n\n\nKan du ikke sende meg oppdaterte bilder av deg og bøkene, og kanskje litt om selve prosessen med dem (hva du vil dele, egentlig, om veien videre fra debutant til ','2026-03-23 11:13:33','general','e54b055221b3b7fd63f71d6914f440e8','2026-03-27 18:22:55','2026-03-27 18:22:55'),(12,'inbox-41','14','Straffen er en klem','randirognmo@yahoo.no','Hei Randi!\n\n\nNå er alt klart for trykk. Vedlagt finner du manus og bokomslaget for en siste godkjenning fra deg. \n\n\nØnsker deg en fin kveld!\n\nAlt godt,\nAnnina','2026-03-17 17:35:35','general','cf08667bff4b203af8eb1666364d4e74','2026-03-27 18:22:55','2026-03-27 18:22:55'),(13,'inbox-43','15','Re: Sv: Manus til vurdering','taran.halvorsen.94@hotmail.com','Supert, Taran! Takk :-) Og ja, det kan du så absolutt.\n\n\nBeste hilsen,\n\nKristine S. Henningsen\nRektor, Forfatterskolen\n+47 411 23 555\n\nOn Mon, Mar 16, 2026 at 11:47 AM Taran Anseth <taran.halvorsen.94','2026-03-16 11:49:33','general','a60895a7f474707d3430d0537eee0a3b','2026-03-27 18:22:55','2026-03-27 18:22:55'),(14,'inbox-45','15','Manus til vurdering','taran.halvorsen.94@hotmail.com','Hei Taran,\n\n\nHåper du har det bra i permisjon :-)\n\n\nJeg lurer på om du vil ta et manus fra Jorunn Kjøde? Ettersom du har sagt du kan følge opp enkelte. Hun har sendt inn tekst, og vil veldig gjerne fo','2026-03-16 10:45:47','general','902a0e48c09dc6625d3b1eabe0053002','2026-03-27 18:22:55','2026-03-27 18:22:55'),(15,'inbox-50','17','Re: Spørsmål ang. innleveringer - barnebok kurs med Gro Dahle','a.jaf@hotmail.no','Hei Gloria,\n\nGodt spørsmål.\n\nDen første innleveringen (frist 31. mars) er til redaktør – det er denne du har fått utsettelse på, og det er her du skal levere teksten din på 1000 ord.\n\nDen andre oppgav','2026-03-25 18:39:33','general','1400b5902bb4de2d7c6e9657ca723811','2026-03-27 18:22:55','2026-03-27 18:22:55'),(16,'inbox-57','19','Re:','hilbar@hotmail.no','Hei Hildegunn!\n\n\nFint å høre :) \n\n\nØnsker deg en fin dag!\n\n\nAlt godt,\nAnnina\nOn Tue, Feb 17, 2026 at 10:27 PM hildegunn barstad <hilbar@hotmail.no> wrote:\n> Hei Annina!\n> Tusen takk. En stressfølelse ','2026-02-18 10:39:18','general','1fbeec147521399bef198bbc24e37dd6','2026-03-27 18:22:55','2026-03-27 18:22:55'),(17,'inbox-59','19','Re: ','hilbar@hotmail.no','Hei Hildegunn!\n\n\n\nTakk for mailen din. Jeg er virkelig lei for å høre at du har blitt innlagt på sykehus og at du går gjennom en så tung periode. Jeg håper inderlig at du snart begynner å føle deg bed','2026-02-16 12:33:47','general','c6a6e5c9ffe85d7ad9cf16ca61993db6','2026-03-27 18:22:55','2026-03-27 18:22:55'),(18,'inbox-62','20','Re: Fråga om kursportalen','magnus@antligen.nu','Hej Magnus!\n\n\nSå tråkigt att höra att du blivit sjuk, krya på dig :) \n\n\nEftersom din redaktör Jenny la tid på coachningen igår och hon kommer att fakturera oss för det innebär det att vi behöver räkna','2026-03-19 12:34:04','general','ead8968be4cbee638cdf3dbb1637a58a','2026-03-27 18:22:55','2026-03-27 18:22:55'),(19,'inbox-64','20','Re: Fråga om kursportalen','magnus@antligen.nu','Hej Magnus!\n\n\nFungerade länken för dig idag för er coachning?\n\n\nAllt gott,\nAnnina\nKursansvarig\n\n\nOn Tue, Mar 10, 2026 at 3:25 PM Magnus Pamp <magnus@antligen.nu> wrote:\n\n> Tack!\n> \n> ---\n> \n> \n> Magnu','2026-03-18 12:13:04','general','3f3f505e1a0a7f753c75c4a6da2b0c34','2026-03-27 18:22:55','2026-03-27 18:22:55'),(20,'inbox-66','20','Re: Fråga om kursportalen','magnus@antligen.nu','Hej Magnus!\n\n\nDet passar Jenny bra. Då har ni ert samtal den 18/3 klockan 9.30 och så lämnar du in dina 5000 ord till mig här via mejl den 13/4.\n\n\nAllt gott,\nAnnina\nKursansvarig\n\n\nOn Tue, Mar 10, 2026','2026-03-10 13:21:05','general','8e07e03204b8bd33bd86b307c677631c','2026-03-27 18:22:55','2026-03-27 18:22:55'),(21,'inbox-67','20','Re: Fråga om kursportalen','magnus@antligen.nu','Hej Magnus!\n\n\nJag ska höra med Jenny så återkommer jag :)\n\n\nAllt gott,\nAnnina\nKursansvarig\n\n\nOn Tue, Mar 10, 2026 at 3:08 PM Magnus Pamp <magnus@antligen.nu> wrote:\n\n> Precis! Funkar det?\n> \n> ---\n> \n','2026-03-10 13:11:18','general','9db1bcca9d739415632eba388ae5e841','2026-03-27 18:22:55','2026-03-27 18:22:55'),(22,'inbox-69','20','Re: Fråga om kursportalen','magnus@antligen.nu','Hej Magnus!\n\n\nFint :) Här är din länk:  https://meet.google.com/uoj-mcjc-fbt \n\n\nMenar du med den 13/4 att du kan lämna in dina 5000 ord då?\n\n\nAllt gott,\nAnnina\nKursansvarig\n\n\nOn Tue, Mar 10, 2026 at 2','2026-03-10 12:56:48','general','bcabc988c67252cf3a6ae32505579a43','2026-03-27 18:22:55','2026-03-27 18:22:55'),(23,'inbox-72','21','Re: Skrivuppgifter för att komma igång','magnus@antligen.nu','Hej Magnus!\n\n\nHar mitt mejl kommit fram? :)\n\n\nAllt gott,\nAnnina\nKursansvarig\n\n\nOn Tue, Mar 24, 2026 at 2:38 PM Post - Easywrite.se <post@easywrite.se> wrote:\n> Hej Magnus!\n> \n> \n> Jag pratade med Ceci','2026-03-25 16:53:18','general','71727d9121c1f70200b4f7e8d8bc3e42','2026-03-27 18:22:55','2026-03-27 18:22:55'),(24,'inbox-73','21','Skrivuppgifter för att komma igång','magnus@antligen.nu','Hej Magnus!\n\n\nJag pratade med Cecilie och hon sa att skrivuppgifterna hon ger är tänkta att hjälpa er kursdeltagare att komma igång med skrivandet. Hon ska fundera på om hon kan komma på någon annan u','2026-03-24 12:38:48','general','a4be9a3c2aa04ed55ffa41570459b276','2026-03-27 18:22:55','2026-03-27 18:22:55'),(25,'inbox-75','22','Re: Avtale med Bookdragons','henrik.aareskjold.84@gmail.com','Hei Henrik\n\nSigner denne og send den til meg. Så ordner jeg videre. \n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Tue, Mar 17, 2026 at 5:11 PM Henrik Aareskjold <henrik.aareskjold.84@','2026-03-25 02:18:05','general','b9f27bcbd89d4a96915328125ba2f01f','2026-03-27 18:22:55','2026-03-27 18:22:55'),(26,'inbox-81','24','Re: Bok','randirognmo@yahoo.no','Hei Randi,\n\nTakk for gode spørsmål.\n\nDet finnes én fastpris på boka, og denne må stå fast i ett år fra utgivelsesdatoen. For eksempel kan du sette prisen til 349 kr. Bokhandlerne kjøper normalt boka f','2026-03-25 13:02:17','general','8d3dc329b8deab7a4d95fe4725178efc','2026-03-27 18:22:55','2026-03-27 18:22:55'),(27,'inbox-83','24','Re: Bok','randirognmo@yahoo.no','Hei Randi,\n\nBeklager sent svar – jeg har vært litt oppslukt i systemutvikling de siste ukene.\n\nAnnina har nå sendt boka di til trykk. Normalt tar trykkprosessen ca. 2–3 uker, så vi nærmer oss ferdig b','2026-03-24 15:31:48','general','4d91e565bcec64a90a60b0863b985479','2026-03-27 18:22:55','2026-03-27 18:22:55'),(28,'inbox-86','24','Re: Bok','randirognmo@yahoo.no','Hei Randi\n\n\nDet ordner jeg, designeren har blitt sykemeldt så jeg må ta ombrekket selv. Regner med at jeg får tatt det til helgen. \n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Sun, M','2026-03-04 11:59:48','general','b99ecc06132fec0da2452560907fae00','2026-03-27 18:22:55','2026-03-27 18:22:55'),(29,'inbox-90','25','Re: årskursets slutt','s.robekk@gmail.com','Hei Synne\n\n\nDere har god tid på antologien, den utgis mest sannsynlig mai 2027. Det kan komme en antologi vi lanserer før det, som er åpen for alle å delta på.\n\nSkoleåret slutter i slutten av juni. \n\n','2026-03-25 02:17:33','general','a39b3b6407aee5ffa4dccc1978807989','2026-03-27 18:22:55','2026-03-27 18:22:55'),(30,'inbox-93','26','Re: Betalingspåminnelse 31069 fra Forfatterskolen AS','s.robekk@gmail.com','Alt ser bra ut på kundesiden din, betalt og alt bra!\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Tue, Mar 10, 2026 at 7:57 PM Synne Røbekk <s.robekk@gmail.com> wrote:\n> Hei.\n> Jeg ha','2026-03-25 02:34:19','general','7db941b51196f9426e360fcdcf1061ec','2026-03-27 18:22:55','2026-03-27 18:22:55'),(31,'inbox-96','27','Re: Novellekoden','rolf@skrivekunst.no','Supert! \n\n\nSkal få betalt den så fort jeg holder på med regnskapet. Akkurat nå går det meste på ren kode.. \n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Mon, Mar 16, 2026 at 6:12 PM R','2026-03-25 02:43:47','general','32a045d6e207efbd1e1f3fcac86fa283','2026-03-27 18:22:55','2026-03-27 18:22:55'),(32,'inbox-98','27','Re: Novellekoden','rolf@skrivekunst.no','Hei Rolf\n\n\nJeg ser at vi fikk inn 104 bøker, du kan fakturere for alle disse. Royalty er 67 kroner per bok. \nNår vi får inn nytt opplag, så sender jeg deg en melding slik at du kan forhåndsfaktuere os','2026-03-15 14:12:17','general','34b5558c5f4bf090c10fcef5f89fa11e','2026-03-27 18:22:55','2026-03-27 18:22:55'),(33,'inbox-99','27','Re: Novellekoden','rolf@skrivekunst.no','Hei Rolf\n\n\nSelvfølgelig, min feil. Trodde du hadde forhåndsfakturert bøkene, men det var tilbake i 2024 ser jeg. Jeg ordner dette iløpet av uken. \n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskol','2026-03-09 13:01:18','general','62c710c08e2ae910e806b0bbe1f85adf','2026-03-27 18:22:55','2026-03-27 18:22:55'),(34,'inbox-102','28','Utvide vps','anton@nordichosting.com','Hi Anton,\n\n\nIs it possible to upgrade our server storage from 500 GB to 1 TB? We are expanding our databases, and I can see that only 11% of the space is currently available.We are moving away from a ','2026-03-25 02:27:48','general','755d007307b7972ada5f2464f2331ff6','2026-03-27 18:22:55','2026-03-27 18:22:55'),(35,'inbox-104','29','Re: Till Annina Forsblom - kursledare finnes','info@johannawistrand.se','Hej Johanna!\n\n\nTack för ditt meddelande :)\n\n\nFör närvarande har vi inte ett behov av en kursledare, men då och då lämnar våra kursdeltagare in manus, oftast på omkring 17 500 eller 70 000 ord, som en ','2026-03-19 13:06:17','general','e235d59d48f93d6a4148d4ed15df5fd7','2026-03-27 18:22:55','2026-03-27 18:22:55'),(36,'inbox-110','32','Re: Viktiga datum och veckans skrivuppgift','pernille.bjarum.privat@gmail.com','Hej igen!\n\n\nTyvärr har Cecilie inte möjlighet att göra den fysiska träffen till ett hybridmöte där man kan delta både på plats och online. Vi hoppas ändå att det kan fungera för dig!\n\n\nHa en fin kväll','2026-03-23 18:27:32','general','f26c4b9375682bce793a7e2bdfca7c6a','2026-03-27 18:22:56','2026-03-27 18:22:56'),(37,'inbox-111','32','Re: Viktiga datum och veckans skrivuppgift','pernille.bjarum.privat@gmail.com','Hej Pernille!\n\n\nJag ska prata med Cecilie i dag och återkommer till dig så snart jag vet mer :)\n\n\nHelena berättade att du undrade om det skulle vara möjligt att ha en till coachning efter att du fått ','2026-03-23 14:41:48','general','11879f651ffc45fc9b9fc684a9623533','2026-03-27 18:22:56','2026-03-27 18:22:56'),(38,'inbox-116','33','Re: Krim manus?','mariwulfsberg@gmail.com','Hei Mari\n\n\nSupert, legger den ved her! Du har vært redaktør for han tidligere. Manuset Hevn. \n\n\nHa en super dag!\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Wed, Mar 11, 2026 at 9:20','2026-03-12 04:33:49','general','532b015ce1f6d7c3a4fedb72b161f850','2026-03-27 18:22:56','2026-03-27 18:22:56'),(39,'inbox-118','33','Krim manus?','mariwulfsberg@gmail.com','Hei Mari\n\n\nHar du mulighet til å ta et krim manus? Det er på rundt 60000 ord og er selvpublisering. Skal også være språkvask eller korrektur. \n\n\nHa en fin dag!\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/','2026-03-11 12:55:17','general','10d111de810895b831cf169af8ee2357','2026-03-27 18:22:56','2026-03-27 18:22:56'),(40,'inbox-120','34','Re: Prosjekt','selmertorgersen@gmail.com','Hei Espen\n\n\nSå hyggelig!\n\n\nDu kan teste det her: \n\n\n https://manusorganisering.forfatterskolen.no/logg-inn \nBrukernavn:  selmertorgersen@gmail.com \nPassord: Espen321\n\n\nHa en super helg! Jeg utvikler v','2026-03-13 16:52:04','general','7d519705475e16583ff318791e8def78','2026-03-27 18:22:56','2026-03-27 18:22:56'),(41,'inbox-126','35','Re: status bok','henrik.aareskjold.84@gmail.com','Supert, forresten alle de andre ebøkene til de som ville ha leseeksemplar har blitt lastet ned. Kun til info :)\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Tue, Mar 10, 2026 at 10:43','2026-03-10 09:47:49','general','3be3164becb8382378fd1c7af903e65e','2026-03-27 18:22:56','2026-03-27 18:22:56'),(42,'inbox-128','35','Re: status bok','henrik.aareskjold.84@gmail.com','Er dette ebok? De to siste?\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Mon, Mar 9, 2026 at 7:31 PM Henrik Aareskjold <henrik.aareskjold.84@gmail.com> wrote:\n> 2 til\n> \n> \n>  michell','2026-03-10 09:43:19','general','3a66cc438757006e8041db322bae7889','2026-03-27 18:22:56','2026-03-27 18:22:56'),(43,'inbox-134','37','Re: Innlogging i På reise med identiteten-kurset','torhildslaatto@gmail.com','Hei Torhild \n\n\nDet er å følge opp elevene, på best mulig måte. Er ikke lett, mange tar bare en titt og ikke svarer på kurset. Har laget et lite mail system inne i admin portalen. Håper det hjelper med','2026-03-12 04:35:47','general','7c417bbba9b64cca9851a805164f498e','2026-03-27 18:22:56','2026-03-27 18:22:56'),(44,'inbox-136','37','Re: Innlogging i På reise med identiteten-kurset','torhildslaatto@gmail.com','Hei \n\n\nHar akkurat sendt deg mail med innlogging, kan du sjekke?\n\n\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Wed, Mar 11, 2026 at 12:46 PM Torhild Slåtto <torhildslaatto@gmail.com>','2026-03-11 11:47:47','general','a6c895e0a78b78d28e1087c58e389f0f','2026-03-27 18:22:56','2026-03-27 18:22:56'),(45,'inbox-138','37','Re: Sirklene i identitet-kurset','torhildslaatto@gmail.com','Hei Torhild\n\n\n\n\n\n\n\nKlikk her så ser du leksjonene.\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\n\nOn Sun, Feb 15, 2026 at 2:03 PM Torhild Slåtto <torhildslaatto@gmail.com> wrote:\n> Ja, fint','2026-02-15 18:16:04','general','e0b7a6671afb065e9541f8d6bbff522d','2026-03-27 18:22:56','2026-03-27 18:22:56'),(46,'inbox-140','37','Re: Sirklene i identitet-kurset','torhildslaatto@gmail.com','Supert, da er denne lagt inn. Har du sett om du har tilgang til admin og alt i orden?\n\n\n--\nMvh\nSven Inge Henningsen\nEasywrite/Forfatterskolen\n\n\n\nOn Sun, Feb 15, 2026 at 9:08 AM Torhild Slåtto <torhild','2026-02-15 11:07:04','general','9d561dba00d17cd3462605a397ff44a7','2026-03-27 18:22:56','2026-03-27 18:22:56'),(47,'inbox-142','37','Re: Sirklene i identitet-kurset','torhildslaatto@gmail.com','Hei Torhild\n\n\nDet går bra for min del. Hvor skal disse illustrasjonene inn? I modulene? \nVet ikke hvor dere skal ha videoen. Satt den i modul1. \n\n\nDu logger inn som admin på denne adressen. : https://','2026-02-13 10:11:04','general','021ef3fe499ecff684e3f8a602f73d1a','2026-03-27 18:22:56','2026-03-27 18:22:56'),(48,'inbox-145','39','Re: Regnskap','torhildslaatto@gmail.com','Hei Torhild\n\n\nKorrekt, du skal nå ha tilgang til tallene. Lagde bare et helt enkelt regnskapsprogram for dette for å ha oversikt, liker ikke prosjektmodulene i regnskapsprogrammene jeg allerede bruker','2026-03-04 15:27:04','general','632e753eca0117bfc7140295cb1d5649','2026-03-27 18:22:56','2026-03-27 18:22:56'),(49,'inbox-147','39','Regnskap','torhildslaatto@gmail.com','Hei Torhild,\n\nJeg har akkurat laget en nettside hvor jeg har summert opp inntekter og utgifter i prosjektet.\n\nVerken Kristine eller jeg har tatt ut noe lønn fra dette prosjektet, og programvarekostnad','2026-03-04 13:17:33','general','cbf970f4bcdd5f4f1720b3d6453e8c23','2026-03-27 18:22:56','2026-03-27 18:22:56'),(50,'inbox-149','40','Re: Utsette innlevering 10 000 ord påbygg','sivennmelen@gmail.com','Hei Siv,\n\nSå leit å høre om faren din – mine varmeste tanker går til deg og familien 🌿\n\nDet går helt bra. Jeg har oppdatert innleveringsdatoen for deg, slik at du får den ekstra tiden du trenger.\n\nTa ','2026-02-20 08:39:17','general','4741ac188b1939b0ff419a59602a2cc8','2026-03-27 18:22:56','2026-03-27 18:22:56'),(51,'inbox-154','43','Re: Faktura','solveig@nygardeliassen.no','Hei Solveig 💛\n\nTakk for at du deler situasjonen din – det er leit å høre at du står i en så krevende periode.\n\nVi prøver å være så fleksible som mulig, og vi kan gi enkelte utsettelser på betalinger. ','2026-03-03 16:39:04','general','8548cd67932262534eb26d5f84b4889f','2026-03-27 18:22:56','2026-03-27 18:22:56'),(52,'inbox-157','44','Re: indiemoon bok solens gudinne','mstensveen@gmail.com','Noe slikt? \n\n\n\n\n\nDette er bare slik at jeg kan fortelle hvordan bilde skal se ut til designeren., \n\n\nMvh\n\nSven Inge Henningsen - Easywrite/Forfatterskolen\nUtvikler\n\n https://cdn.helpwise.io/userSignat','2026-02-18 17:29:35','general','dd2c9a402789401b5dcf4e6c59e2a6a3','2026-03-27 18:22:56','2026-03-27 18:22:56'),(53,'inbox-159','44','Re: indiemoon bok solens gudinne','mstensveen@gmail.com','Hei Marit\n\n\nJeg har akkurat begynt å se på hvordan coveret skal se ut\n\n\nSolens gudinne\n\n\n\n \nJeg tror du vil ha delen til venstre på forsiden? Eller hvordan har du tenkt med coveret?\n\n\n\n\nMvh\n\nSven Inge','2026-02-18 17:10:49','general','c3ee4cbb53d80a594eb3ecb23edb1b62','2026-03-27 18:22:56','2026-03-27 18:22:56'),(54,'inbox-166','47','Re: Sveriges årskurs betalningar','post@easywrite.se','Hei \n\nDisse er nå opprettet.\n\n\nMvh\n\nSven Inge Henningsen - Easywrite/Forfatterskolen\nUtvikler\n\n https://cdn.helpwise.io/userSignatures/07ee10796cb17f5e70b7.1622489977.a84ba469b71c48ae08b0 \n\n\nOn Mon, F','2026-02-16 20:28:32','general','7123ff32c67af99a2fbe4bee0330c5e8','2026-03-27 18:22:56','2026-03-27 18:22:56'),(55,'inbox-171','49','Re: Utgiven elev','pernilla.yasin@gmail.com','Hej Pernilla!\n\n\nVad roligt att höra från dig och stort grattis igen till att din bok snart ges ut :) \n\n\nTack för att du skickade texten, bilden på dig och omslaget! Jag återkommer när informationen om','2026-01-28 19:03:04','general','6101f77c5d3d20ceacca30f4a381b9cf','2026-03-27 18:22:56','2026-03-27 18:22:56'),(56,'inbox-173','49','Re: Utgiven elev','pernilla.yasin@gmail.com','Hej Pernilla!\n\n\nDet passar utmärkt :)\n\n\nTack snälla för dina fina ord!\n\n\nAllt gott,\nAnnina\nKursansvarig\n\n\nOn Mon, Jan 20, 2025 at 9:56 PM Pernilla Yasin <pernilla.yasin@gmail.com> wrote:\n> Hej Annina!','2025-01-20 20:38:04','general','81a150a7624f2c051326b49a9a149cc2','2026-03-27 18:22:56','2026-03-27 18:22:56'),(57,'inbox-175','49','Utgiven elev','pernilla.yasin@gmail.com','Hej igen Pernilla!\n\n\n\nNär du har möjlighet, skulle du kunna skicka en kort presentation av dig själv och din debutbok samt bifoga en bild på dig? Skulle du även kunna svara på följande frågor?:\n\n\n\n\n 1','2025-01-16 19:31:04','general','4d07227f73445a2f4fb7948c5662791d','2026-03-27 18:22:56','2026-03-27 18:22:56'),(58,'inbox-255','119','Fw: Bøker elever har skrevet og gitt ut','camilla.b@forfatterskolen.no','\n\n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, February 15, 2022 at 08:37 PM Anne Kristiansen Rønning <annekriro@gmail.com [annekriro@gmail.com','2022-02-15 20:27:04','general','a7940328b0734ba4e954085a8f1380dc','2026-03-27 18:22:56','2026-03-27 18:22:56'),(59,'inbox-261','121','Re: Årskurset','martheme@me.com','Hei Marthe! \n\nDet stemmer :) Info til alle kommer snart - men eneste du trenger å gjøre er å si hvilket kurs du ønsker, så legger jeg deg til :) \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf:','2022-02-15 15:05:19','general','f1eaa455cd017fe165e0f5cb01516045','2026-03-27 18:22:56','2026-03-27 18:22:56'),(60,'inbox-264','122','Endre navn','siljewn@gmail.com','Hei! \n\n\nJeg så kommentaren din ang. navnendring i word for pc. \n\n\nFungerer dette: https://answers.microsoft.com/en-us/msoffice/forum/all/i-need-to-change-my-name-for-track-changes/d5a39bbc-a2cd-4c8e-b','2022-02-15 14:05:04','general','cf8cef2fe2fddcabf1da2679cf8c7543','2026-03-27 18:22:56','2026-03-27 18:22:56'),(61,'inbox-266','123','Re: webinar_første kursdag','karenlouisemartinsen@gmail.com','Hei Karen! \n\n\nTusen takk! 💛 \n\n\nSå fint å høre at du likte webinaret i dag! Skjønner absolutt det kan være overveldende med både chat og info på en gang! Det tar litt tid å vende seg til, men etterhver','2022-02-15 14:37:34','general','952e123473fda9f65bcfd73020e31723','2026-03-27 18:22:56','2026-03-27 18:22:56'),(62,'inbox-271','126','Re: Årskurset 2022: Kursplan med tema!','langsethluth@gmail.com','Jeg har tatt vek pinnen nå! Hvilken nettleser bruker du? \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, February 15, 2022 at 11:22 AM Tone Luth ','2022-02-15 10:28:47','general','0317705785def99e08b48270adc64898','2026-03-27 18:22:56','2026-03-27 18:22:56'),(63,'inbox-274','126','Re: Årskurset 2022: Kursplan med tema!','langsethluth@gmail.com','Hei Tone! \n\n\nHar du kommet inn igjen? Prøv å avslutt nettleseren og gå inn på lenken på nytt! \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, Feb','2022-02-15 09:54:04','general','b5e67eb995ca3a4c74a6044b540f5306','2026-03-27 18:22:56','2026-03-27 18:22:56'),(64,'inbox-277','127','Re: Årskurset 2022: Kursplan med tema!','mphrossi@yahoo.no','Hei Maria! \n\n\nÅrskurset gjelder for alle sjangre, det er ganske mange i år som skriver sakprosa :) Romankurset er det som følger med årskurset uansett - det er rettet mot skjønnlitteratur - og i tille','2022-02-15 14:21:48','general','9d0a16dcafed711d06eb841a44bc3f46','2026-03-27 18:22:56','2026-03-27 18:22:56'),(65,'inbox-280','128','Re: Årskurset 2022: Kursplan med tema!','henriette@h5.no','Hei Henriette! \n\n\nDa har jeg forhørt meg ang. redaktør og prisanslag basert på opplysningene dine om manus og ønske om redaktøroppfølging :) \n\n\nEstimert prisforslag for gjennomgang av manus på 100 sid','2022-02-15 15:14:05','general','ddcc3cfb90029d2681f7e06593031ee3','2026-03-27 18:22:56','2026-03-27 18:22:56'),(66,'inbox-282','128','Re: Årskurset 2022: Kursplan med tema!','henriette@h5.no','Hei Henriette! \n\n\nDu har uansett 14 dagers angrerett, så det går fint :) Jeg oppdaterer deg straks! \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Monday','2022-02-14 23:15:48','general','84f40c9fd893131fbff29923070820c9','2026-03-27 18:22:56','2026-03-27 18:22:56'),(67,'inbox-285','129','Re: Årskurset 2022: Kursplan med tema!','lindafalcholaisen@gmail.com','Hva slags feilmelding får du? Det er også mulig å kopiere fra word og lime inn i Easywrite :) \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, Feb','2022-02-15 14:40:34','general','5cc60aaaaedb90e32bb6f6e137b26f04','2026-03-27 18:22:56','2026-03-27 18:22:56'),(68,'inbox-288','129','Re: Årskurset 2022: Kursplan med tema!','lindafalcholaisen@gmail.com','Hei Linda! \n\n\nJeg har informert support om feilen, kommer straks tilbake til deg! \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, February 15, 20','2022-02-15 14:30:48','general','ae6549fbdd5408de9cda73208ff1b9ee','2026-03-27 18:22:56','2026-03-27 18:22:56'),(69,'inbox-289','129','Fw: Re: Årskurset 2022: Kursplan med tema!','lindafalcholaisen@gmail.com','Flere melder om feilmelding når de skal laste ned Easywrite - appen. \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, February 15, 2022 at 01:09 P','2022-02-15 14:30:19','general','dedd540942c1df6201518d1848c6a060','2026-03-27 18:22:56','2026-03-27 18:22:56'),(70,'inbox-292','129','Re: Årskurset 2022: Kursplan med tema!','lindafalcholaisen@gmail.com','Her: www.pilotleser.no [//www.pilotleser.no] :) \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesday, February 15, 2022 at 11:47 AM linda falch olaisen','2022-02-15 11:08:18','general','8a86dfb14dc3ba0791705bf8816d1e6a','2026-03-27 18:22:56','2026-03-27 18:22:56'),(71,'inbox-296','130','Re:','aidasol91@gmail.com','Det passer for eleven 15.30 eller 16.00, går det? :) \n\n\nMvh,\nCamilla Sandmo\nSjefredaktør // Elevkontakt\nTlf: 463 32 692\n\nwww.forfatterskolen.no\nOn Tuesd